const C_NUM: i64 = -251237303637201; const C_DEN: i64 = 1125899906842624;

fn b2b256(parts: &[&[u8]]) -> Vec<u8> {
    let mut h = blake2b_ref::Blake2bBuilder::new(32).build();
    for p in parts { h.update(p); } let mut o=[0u8;32]; h.finalize(&mut o); o.to_vec()
}
fn ev_le(index: u64, sigma: &[u8]) -> [u8;64] {
    // standard BLAKE2b-512 (== blake2::Blake2b512) via blake2b-ref, 64-byte output
    let mut h = blake2b_ref::Blake2bBuilder::new(64).build();
    h.update(b"map"); h.update(MSGP); h.update(&index.to_le_bytes()); h.update(sigma);
    let mut o=[0u8;64]; h.finalize(&mut o); o
}
// PHASE 2 - the SNARK-lottery target (replaces the per-index rational Taylor). The per-party target
// T = ceil(T*), T* = 2^512*(1-(1-phi_f)^w), (1-phi_f)^w = exp(w*c). Computed via a FIXED-POINT
// integer Taylor for exp(w*c) at scale 2^768 (no num-rational/gcd - that costs ~70% of a block);
// the per-index eligibility check is then a single 512-bit integer compare `ev < T`.
// Differential-tested == is_lottery_won on all 2330 real preview indices (spike/phase2/).
const SHIFT: u32 = 768;
fn compute_target(stake: u64) -> BigInt {
    let s = BigInt::from(1u8) << SHIFT;
    let xa = BigInt::from(stake) * BigInt::from(C_NUM); // < 0
    let xb = BigInt::from(TOTAL) * BigInt::from(C_DEN); // > 0
    let mut t = s.clone(); let mut acc = s.clone(); let mut n: u64 = 0;
    loop {
        n += 1;
        t = &t * &xa; t = &t / &xb; t = &t / &BigInt::from(n);  // t_k = t_{k-1} * x / k
        if t == BigInt::from(0u8) { break; }
        acc += &t;
        if n > 400 { break; }
    }
    let e512 = &acc >> (SHIFT - 512);            // floor(2^512 * exp(x))
    (BigInt::from(1u8) << 512) - e512            // T = 2^512 - floor(2^512*exp(x)) = ceil(T*)
}
fn ev_won(ev_bytes: [u8;64], target: &BigInt) -> bool {
    BigInt::from_bytes_le(Sign::Plus, &ev_bytes) < *target
}

fn check_compute_hash() -> bool {
    let mut h = Sha256::new();
    for (k,v) in PARTS { sha2::Digest::update(&mut h, k); sha2::Digest::update(&mut h, v); }
    let digest = h.finalize();
    // signed_message (ascii hex of digest) == first 64 bytes of MSGP
    let hex = b"0123456789abcdef";
    let mut sm=[0u8;64];
    for i in 0..32 { sm[2*i]=hex[(digest[i]>>4) as usize]; sm[2*i+1]=hex[(digest[i]&0xf) as usize]; }
    sm[..] == MSGP[..SIGNED_MESSAGE_LEN]
}
fn check_aggregate_bls() -> bool {
    let s0=G1Affine::from_compressed(&SIGMA0); let s1=G1Affine::from_compressed(&SIGMA1);
    let v0=G2Affine::from_compressed(&MVK0); let v1=G2Affine::from_compressed(&MVK1);
    if bool::from(s0.is_none()|s1.is_none()|v0.is_none()|v1.is_none()) { return false; }
    let agg_sig=G1Affine::from(G1Projective::from(s0.unwrap())+G1Projective::from(s1.unwrap()));
    let agg_mvk=G2Affine::from(G2Projective::from(v0.unwrap())+G2Projective::from(v1.unwrap()));
    let h:G1Affine=<G1Projective as HashToCurve<ExpandMsgXmd<Sha256>>>::hash_to_curve(MSGP,b"").into();
    pairing(&agg_sig,&G2Affine::generator()) == pairing(&h,&agg_mvk)
}
fn check_eligibility_quorum() -> bool {
    // PHASE 2: per-party target (computed ONCE per distinct signer) + a 512-bit integer compare
    // per index. ~40M cycles for all 2330 indices (1.1% of a block), vs ~2.37e9 (68%) for the
    // naive per-index Taylor. Exact: (ev<T) == is_lottery_won(ev) on all 2330 real indices.
    let t0 = compute_target(STAKE0);
    let t1 = compute_target(STAKE1);
    let mut count=0usize;
    for &i in IDX0 { if !ev_won(ev_le(i,&SIGMA0), &t0) { return false; } count+=1; }
    for &i in IDX1 { if !ev_won(ev_le(i,&SIGMA1), &t1) { return false; } count+=1; }
    count >= K
}
fn check_merkle() -> bool {
    fn parent(i:usize)->usize{(i-1)/2} fn sibling(i:usize)->usize{if i%2==1{i+1}else{i-1}}
    fn npow2(n:usize)->usize{let mut p=1usize; while p<n{p<<=1;} p}
    let npo=npow2(NR_LEAVES); let nr_nodes=NR_LEAVES+npo-1;
    let mut oi: Vec<usize>=MINDICES.iter().map(|i| i+npo-1).collect();
    let mut leaves: Vec<Vec<u8>>=vec![b2b256(&[MLEAF0]),b2b256(&[MLEAF1])];
    let mut vals: Vec<Vec<u8>>=vec![MVAL0.to_vec()];
    let zero=b2b256(&[&[0u8]]); let mut idx=oi[0];
    while idx>0 {
        let mut nh:Vec<Vec<u8>>=Vec::new(); let mut ni:Vec<usize>=Vec::new(); let mut i=0; idx=parent(idx);
        while i<oi.len() {
            ni.push(parent(oi[i]));
            if oi[i]&1==0 { let h=b2b256(&[&vals[0],&leaves[i]]); nh.push(h); vals.remove(0); }
            else { let sib=sibling(oi[i]);
                if i<oi.len()-1 && oi[i+1]==sib { nh.push(b2b256(&[&leaves[i],&leaves[i+1]])); i+=1; }
                else if sib<nr_nodes { let h=b2b256(&[&leaves[i],&vals[0]]); nh.push(h); vals.remove(0); }
                else { nh.push(b2b256(&[&leaves[i],&zero])); } }
            i+=1;
        }
        leaves=nh; oi=ni;
    }
    leaves.len()==1 && leaves[0].as_slice()==&AVK_ROOT[..]
}
/// The single assembled entrypoint: cert valid under (AVK_ROOT, TOTAL) => Some(next checkpoint).
fn verify_certificate() -> Option<([u8;32],u64)> {
    if !check_compute_hash() { return None; }
    if !check_aggregate_bls() { return None; }
    if !check_eligibility_quorum() { return None; }
    if !check_merkle() { return None; }
    Some((NEXT_ROOT, NEXT_TOTAL))
}
fn read_state(src: Source) -> Option<(u64,[u8;32],u64)> {
    let d = load_cell_data(0, src).ok()?;
    if d.len()!=48 { return None; }
    let mut e=[0u8;8]; e.copy_from_slice(&d[0..8]);
    let mut r=[0u8;32]; r.copy_from_slice(&d[8..40]);
    let mut t=[0u8;8]; t.copy_from_slice(&d[40..48]);
    Some((u64::from_le_bytes(e), r, u64::from_le_bytes(t)))
}
fn program_entry() -> i8 {
    let _ = load_witness_args(0, Source::GroupInput);
    let (in_epoch, in_root, in_total) = match read_state(Source::GroupInput) { Some(s)=>s, None=>return 1 };
    if in_root != AVK_ROOT || in_total != TOTAL || in_epoch != EPOCH { return 2; }  // cert verifies vs THIS avk
    if !check_compute_hash() { return 10; }
    if !check_aggregate_bls() { return 11; }
    if !check_eligibility_quorum() { return 12; }
    if !check_merkle() { return 13; }
    let (next_root, next_total) = (NEXT_ROOT, NEXT_TOTAL);
    let (out_epoch, out_root, out_total) = match read_state(Source::GroupOutput) { Some(s)=>s, None=>return 4 };
    if out_epoch != in_epoch+1 || out_root != next_root || out_total != next_total { return 5; }  // checkpoint rolled forward
    0
}
